import { Composio } from '@composio/core';

import { createAuthCallbackHandler } from './api/auth-callback';
import { createComposioWebhookHandler } from './api/composio-webhook';
import { createApiHandler } from './api/router';
import { createSlackComposioAgent } from './agent/slack-composio-agent';
import { createSlackbotSetupService } from './composio/slackbot-setup';
import { loadConfig } from './config/env';
import { createSlackTransport } from './slack/transport';
import { createFileStore } from './store/file-store';

const config = loadConfig();
const store = await createFileStore(config.dataDir);
const composio = new Composio({ apiKey: config.composioApiKey });
const slack = createSlackTransport({ config, store });
const agent = createSlackComposioAgent({ config, slack, store });
const slackbotSetup = createSlackbotSetupService({ composio, config, store });
const composioWebhook = createComposioWebhookHandler({ agent, config, store });
const authCallback = createAuthCallbackHandler({ agent, slack, store });

const server = Bun.serve({
  hostname: config.host,
  port: config.port,
  fetch: createApiHandler({ authCallback, composioWebhook, slackbotSetup }),
});

console.log(`Composio Slack Pi bot listening on http://${server.hostname}:${server.port}`);
console.log(`Setup URL: ${config.appUrl}/setup/slackbot/start`);

import 'dotenv/config';
import { join } from 'node:path';

const DEFAULT_SLACKBOT_BOT_SCOPES = [
  'app_mentions:read',
  'assistant:write',
  'channels:history',
  'channels:read',
  'chat:write',
  'files:read',
  'files:write',
  'groups:history',
  'groups:read',
  'im:history',
  'im:read',
  'im:write',
  'links:read',
  'links:write',
  'mpim:history',
  'mpim:read',
  'mpim:write',
  'reactions:read',
  'reactions:write',
  'team:read',
  'users:read',
];

const DEFAULT_SLACKBOT_USER_SCOPES = [
  'channels:history',
  'channels:read',
  'files:read',
  'groups:history',
  'groups:read',
  'im:history',
  'im:read',
  'mpim:history',
  'mpim:read',
  'reactions:read',
  'search:read',
  'search:read.public',
  'users.profile:read',
  'users:read',
  'users:read.email',
];

export interface AppConfig {
  appUrl: string;
  composioApiKey: string;
  composioToolkits?: string[];
  composioAuthConfigs?: Record<string, string>;
  autoAnalyzeMainUserMessages: boolean;
  autoPromoteFirstMainUser: boolean;
  composioWorkbenchEnabled: boolean;
  dataDir: string;
  host: string;
  piCwd: string;
  ignoreReactionName: string;
  mainSlackUserIds: string[];
  piWorkbenchEnabled: boolean;
  port: number;
  postPublicAuthDmNotice: boolean;
  slackBotUserId?: string;
  slackbotAuthConfigId?: string;
  slackbotAuthConfigName: string;
  slackbotBotScopes: string[];
  slackbotSharedConnectedAccountId?: string;
  slackbotTransportUserId?: string;
  slackbotUserScopes: string[];
}

function requiredEnv(name: string): string {
  const value = process.env[name];
  if (!value || value.trim().length === 0) {
    throw new Error(`Missing required environment variable ${name}`);
  }
  return value.trim();
}

function optionalList(name: string): string[] | undefined {
  return optionalRawList(name)?.map((value) => value.toLowerCase());
}

function optionalRawList(name: string): string[] | undefined {
  const raw = process.env[name];
  if (!raw) return undefined;

  const values = raw
    .split(',')
    .map((value) => value.trim())
    .filter(Boolean);

  return values.length > 0 ? values : undefined;
}

function booleanEnv(name: string, defaultValue: boolean): boolean {
  const raw = process.env[name];
  if (!raw) return defaultValue;
  return ['1', 'true', 'yes', 'y', 'on'].includes(raw.trim().toLowerCase());
}

function numberEnv(name: string, defaultValue: number): number {
  const raw = process.env[name];
  if (!raw) return defaultValue;

  const value = Number(raw);
  if (!Number.isFinite(value)) {
    throw new Error(`Invalid numeric environment variable ${name}: ${raw}`);
  }
  return value;
}

function optionalEnv(name: string): string | undefined {
  const value = process.env[name];
  return value && value.trim() ? value.trim() : undefined;
}

function parseAuthConfigs(): Record<string, string> | undefined {
  const configs: Record<string, string> = {};

  const json = process.env.COMPOSIO_AUTH_CONFIGS_JSON;
  if (json && json.trim() && json.trim() !== '{}') {
    const parsed = JSON.parse(json) as Record<string, unknown>;
    for (const [toolkit, authConfigId] of Object.entries(parsed)) {
      if (typeof authConfigId === 'string' && authConfigId.trim()) {
        configs[toolkit.toLowerCase()] = authConfigId.trim();
      }
    }
  }

  for (const [key, value] of Object.entries(process.env)) {
    if (!key.startsWith('COMPOSIO_AUTH_CONFIG_') || key === 'COMPOSIO_AUTH_CONFIGS_JSON') {
      continue;
    }
    if (!value || !value.trim()) continue;

    const toolkit = key
      .slice('COMPOSIO_AUTH_CONFIG_'.length)
      .toLowerCase()
      .replaceAll('__', '-')
      .replaceAll('_', '');

    configs[toolkit] = value.trim();
  }

  return Object.keys(configs).length > 0 ? configs : undefined;
}

export function loadConfig(): AppConfig {
  const port = numberEnv('PORT', 3000);
  const rawAppUrl = optionalEnv('APP_URL');
  const appUrl = (!rawAppUrl || rawAppUrl.includes('your-public-url.example.com')
    ? `http://localhost:${port}`
    : rawAppUrl
  ).replace(/\/$/, '');
  const dataDir = process.env.DATA_DIR?.trim() || '.data';
  const piWorkbenchEnabled = booleanEnv('PI_LOCAL_WORKBENCH_ENABLED', false);

  return {
    appUrl,
    autoAnalyzeMainUserMessages: booleanEnv('AUTO_ANALYZE_MAIN_USER_MESSAGES', true),
    autoPromoteFirstMainUser: booleanEnv('AUTO_PROMOTE_FIRST_MAIN_USER', true),
    composioApiKey: requiredEnv('COMPOSIO_API_KEY'),
    composioToolkits: optionalList('COMPOSIO_TOOLKITS'),
    composioAuthConfigs: parseAuthConfigs(),
    composioWorkbenchEnabled: booleanEnv('COMPOSIO_WORKBENCH_ENABLED', true),
    dataDir,
    host: process.env.HOST?.trim() || '0.0.0.0',
    ignoreReactionName: process.env.IGNORE_REACTION_NAME?.trim() || 'ignore',
    mainSlackUserIds: optionalRawList('MAIN_SLACK_USER_IDS') ?? [],
    piCwd: process.env.PI_CWD?.trim() || (piWorkbenchEnabled ? join(dataDir, 'pi-local-workbench') : process.cwd()),
    piWorkbenchEnabled,
    port,
    postPublicAuthDmNotice: booleanEnv('POST_PUBLIC_AUTH_DM_NOTICE', true),
    slackBotUserId: optionalEnv('SLACK_BOT_USER_ID'),
    slackbotAuthConfigId: optionalEnv('SLACKBOT_AUTH_CONFIG_ID'),
    slackbotAuthConfigName: optionalEnv('SLACKBOT_AUTH_CONFIG_NAME') ?? 'slackbot-expanded-scopes',
    slackbotBotScopes: optionalRawList('SLACKBOT_BOT_SCOPES') ?? DEFAULT_SLACKBOT_BOT_SCOPES,
    slackbotSharedConnectedAccountId: optionalEnv('SLACKBOT_SHARED_CONNECTED_ACCOUNT_ID'),
    slackbotTransportUserId: optionalEnv('SLACKBOT_TRANSPORT_USER_ID'),
    slackbotUserScopes: optionalRawList('SLACKBOT_USER_SCOPES') ?? DEFAULT_SLACKBOT_USER_SCOPES,
  };
}

import { createHash, randomUUID } from 'node:crypto';

import { Composio } from '@composio/core';

import { jsonResponse } from '../api/http';
import type { AppConfig } from '../config/env';
import { htmlPages } from '../html/pages';
import { htmlFileResponse, htmlTemplateResponse } from '../html/render';
import { proxySlack } from '../slack/transport';
import type { Store } from '../store/file-store';
import { firstString, jsonObject } from '../utils/decode';
import type { JsonObject, JsonValue } from '../utils/json';
import { createComposioApiClient } from './api';

type ComposioSession = Awaited<ReturnType<Composio['sessions']['create']>>;

interface SharedSlackbotAuthorizeOptions {
  callbackUrl: string;
  experimental: {
    accountType: 'SHARED';
  };
}

interface SlackbotSetupDeps {
  composio: Composio;
  config: AppConfig;
  store: Store;
}

export interface SlackbotSetupService {
  completeSetup(url: URL): Promise<Response>;
  ensureSlackbotAuthConfig(): Promise<string | undefined>;
  ensureSlackbotTriggers(connectedAccountId: string): Promise<void>;
  ensureWebhookSubscription(): Promise<void>;
  startSetup(): Promise<Response>;
}

/**
 * Owns the install-time Slackbot plumbing:
 * - create/reuse a managed Slackbot auth config with the requested scopes
 * - request a shared Slackbot connection
 * - persist the team-scoped connected account
 * - ensure Composio webhook subscription + Slackbot triggers exist
 */
export function createSlackbotSetupService({ composio, config, store }: SlackbotSetupDeps): SlackbotSetupService {
  const composioApi = createComposioApiClient(config);

  const ensureSlackbotAuthConfig = async (): Promise<string | undefined> => {
    if (config.slackbotAuthConfigId) {
      return config.slackbotAuthConfigId;
    }

    const botScopes = uniqueSorted(config.slackbotBotScopes);
    const userScopes = uniqueSorted(config.slackbotUserScopes);
    if (botScopes.length === 0 && userScopes.length === 0) {
      return undefined;
    }

    const name = slackbotAuthConfigName(config, botScopes, userScopes);
    const existing = await composio.authConfigs.list({ toolkit: 'slackbot', isComposioManaged: true, limit: 100 });
    const match = authConfigItems(existing).find((item) => item.name === name);
    if (match?.id) {
      return match.id;
    }

    const created = await composio.authConfigs.create('slackbot', {
      type: 'use_composio_managed_auth',
      name,
      credentials: {
        scopes: botScopes,
        user_scopes: userScopes,
      },
    });
    console.log(`Created Slackbot Composio auth config ${created.id} (${name})`);
    return created.id;
  };

  const ensureWebhookSubscription = async (): Promise<void> => {
    const webhookUrl = `${config.appUrl}/webhooks/composio`;
    const body = {
      webhook_url: webhookUrl,
      enabled_events: ['composio.trigger.message'],
      version: 'V3',
    };

    const existing = await composioApi.request('/api/v3.1/webhook_subscriptions', { method: 'GET' });
    const subscription = firstObjectItem(existing?.items);
    const subscriptionId = firstString(subscription?.id);

    if (subscriptionId) {
      await composioApi.request(`/api/v3.1/webhook_subscriptions/${subscriptionId}`, {
        method: 'PATCH',
        body,
      });
      return;
    }

    await composioApi.request('/api/v3.1/webhook_subscriptions', {
      method: 'POST',
      body,
    });
  };

  const ensureSlackbotTriggers = async (connectedAccountId: string): Promise<void> => {
    const connectedAccount = await composioApi.request(`/api/v3/connected_accounts/${connectedAccountId}`, { method: 'GET' });
    const ownerUserId = firstString(connectedAccount?.user_id);
    if (!ownerUserId) {
      throw new Error(`Could not determine owner user_id for connected account ${connectedAccountId}`);
    }

    await upsertTrigger(composioApi.request, 'SLACKBOT_CHANNEL_MESSAGE_RECEIVED', connectedAccountId, ownerUserId, {
      is_bot_message: false,
    });

    await upsertTrigger(composioApi.request, 'SLACKBOT_DIRECT_MESSAGE_RECEIVED', connectedAccountId, ownerUserId, {});
  };

  const startSetup = async (): Promise<Response> => {
    const setupId = randomUUID();
    const setupUserId = `setup:slackbot:${setupId}`;
    const authConfigId = await ensureSlackbotAuthConfig();
    const session = await composio.sessions.create(setupUserId, {
      toolkits: ['slackbot'],
      authConfigs: authConfigId ? { slackbot: authConfigId } : {},
      manageConnections: true,
      workbench: { enable: false },
    });
    await store.setSlackbotSetup(setupId, session.sessionId, setupUserId);

    const connectionRequest = await session.authorize('slackbot', sharedSlackbotAuthorizeOptions(config, setupId));
    if (!connectionRequest.redirectUrl) {
      return jsonResponse({ ok: false, error: 'missing_redirect_url' }, 500);
    }

    return Response.redirect(connectionRequest.redirectUrl, 302);
  };

  const completeSetup = async (url: URL): Promise<Response> => {
    const setupId = url.searchParams.get('setup');
    const connectedAccountId = url.searchParams.get('connected_account_id');
    const status = url.searchParams.get('status');
    const setup = setupId ? store.getSlackbotSetup(setupId) : undefined;

    if (!setupId || !setup) {
      return htmlFileResponse(htmlPages.slackbotSetupExpired, 400);
    }

    if (!connectedAccountId || status !== 'success') {
      return htmlFileResponse(htmlPages.slackbotSetupFailed, 400);
    }

    const setupSession = await composio.sessions.use(setup.sessionId);
    await setupSession.update({ connectedAccounts: { slackbot: [connectedAccountId] } });
    const slackAuth = await slackAuthTest(setupSession);
    const teamId = slackAuth.teamId;
    await composio.experimental.updateAcl(connectedAccountId, { allowAllUsers: true });

    await store.setSlackbotConnection(teamId, connectedAccountId, {
      botUserId: slackAuth.botUserId,
      teamName: slackAuth.teamName,
    });
    await store.deleteSlackbotSetup(setupId);

    await ensureWebhookSubscription().catch((error) => {
      console.error('Failed to configure Composio webhook subscription after setup', error);
    });
    await ensureSlackbotTriggers(connectedAccountId).catch((error) => {
      console.error('Failed to create Slackbot triggers after setup', error);
    });

    return htmlTemplateResponse(htmlPages.slackbotConnected, { teamName: slackAuth.teamName ?? teamId });
  };

  return {
    completeSetup,
    ensureSlackbotAuthConfig,
    ensureSlackbotTriggers,
    ensureWebhookSubscription,
    startSetup,
  };
}

function sharedSlackbotAuthorizeOptions(config: AppConfig, setupId: string): SharedSlackbotAuthorizeOptions {
  const callbackUrl = new URL('/setup/slackbot/callback', config.appUrl);
  callbackUrl.searchParams.set('setup', setupId);

  return {
    callbackUrl: callbackUrl.toString(),
    experimental: {
      accountType: 'SHARED',
    },
  };
}

function slackbotAuthConfigName(config: AppConfig, botScopes: string[], userScopes: string[]): string {
  const scopeHash = createHash('sha256')
    .update(JSON.stringify({ botScopes, userScopes }))
    .digest('hex')
    .slice(0, 8);
  return `${config.slackbotAuthConfigName}-${scopeHash}`;
}

async function slackAuthTest(session: ComposioSession): Promise<{ botUserId?: string; teamId: string; teamName?: string }> {
  return decodeSlackAuthTest(await proxySlack(session, 'auth.test', {}));
}

function decodeSlackAuthTest(response: unknown): { botUserId?: string; teamId: string; teamName?: string } {
  const responseObject = jsonObject(response) ?? {};
  const data = jsonObject(responseObject.data) ?? responseObject;
  const nestedData = jsonObject(data.data);

  if (data.ok === false) {
    throw new Error(`Slack auth.test failed: ${firstString(data.error) ?? JSON.stringify(data)}`);
  }

  const teamId = firstString(data.team_id, data.teamId, nestedData?.team_id, nestedData?.teamId);
  if (!teamId) {
    throw new Error(`Slack auth.test did not return team_id: ${JSON.stringify(data)}`);
  }

  return {
    botUserId: firstString(data.user_id, data.userId, data.bot_user_id, data.botUserId, nestedData?.user_id),
    teamId,
    teamName: firstString(data.team, data.team_name, data.teamName, nestedData?.team),
  };
}

function authConfigItems(value: unknown): Array<{ id?: string; name?: string }> {
  const record = jsonObject(value) ?? {};
  const items = Array.isArray(record.items) ? record.items : [];
  return items.flatMap((item): Array<{ id?: string; name?: string }> => {
    const object = jsonObject(item);
    if (!object) return [];
    return [
      {
        id: firstString(object.id),
        name: firstString(object.name),
      },
    ];
  });
}

function uniqueSorted(values: string[]): string[] {
  return [...new Set(values.map((value) => value.trim()).filter(Boolean))].sort();
}

function firstObjectItem(value: JsonValue | undefined): JsonObject | undefined {
  return Array.isArray(value) ? jsonObject(value[0]) : undefined;
}

async function upsertTrigger(
  request: (path: string, init: { method: string; body?: JsonValue }) => Promise<JsonObject | undefined>,
  slug: string,
  connectedAccountId: string,
  userId: string,
  triggerConfig: JsonObject,
): Promise<void> {
  await request(`/api/v3/trigger_instances/${slug}/upsert`, {
    method: 'POST',
    body: {
      connected_account_id: connectedAccountId,
      user_id: userId,
      trigger_config: triggerConfig,
    },
  });
}

import { Composio } from '@composio/core';
import { PiProvider, type PiSessionToolCapabilities } from '@composio/experimental';

import {
  authCallbackUrl,
  isSlackbotToolkit,
  isSlackbotToolSlug,
  isUserSlackToolSlug,
  normalizeRequestedToolkits,
  normalizeSearchToolkits,
  normalizeToolkitKey,
  normalizeToolkitStates,
  toolkitIsConnected,
} from './helpers';
import type { AppConfig } from '../config/env';
import { assertSlackbotManualAcl } from '../slack/acl';
import type { NormalizedSlackTriggerEvent } from '../slack/events';
import type { Store } from '../store/file-store';
import type { JsonObject } from '../utils/json';
import type { ComposioRouting } from './routing';

type ComposioSession = Awaited<ReturnType<Composio['sessions']['create']>>;
type HandleAuthLinks = <T>(value: T, sourceTool: string, requestedToolkits?: string[]) => Promise<T>;

interface ComposioRoutingWithPiProviderDeps {
  composio: Composio;
  config: AppConfig;
  store: Store;
}

interface CapabilityDeps {
  config: AppConfig;
  event: NormalizedSlackTriggerEvent;
  handleAuthLinks: HandleAuthLinks;
  userSession: ComposioSession;
}

const piProvider = new PiProvider();

/**
 * Side-by-side experiment for using @composio/experimental's Pi provider.
 *
 * This uses the newer capability API rather than a fake session adapter:
 * app code owns search normalization, execution policy, connection state,
 * authorization, auth-link routing, and Slackbot shared-connection ACLs.
 */
export function createComposioRoutingWithPiProvider({
  composio,
  config,
  store,
}: ComposioRoutingWithPiProviderDeps): ComposioRouting {
  const getOrCreateUserSession = async (
    event: NormalizedSlackTriggerEvent,
    userId: string,
    threadKey: string,
  ): Promise<ComposioSession> => {
    const slackbotConnectedAccountId = slackbotConnectedAccountIdForEvent(config, store, event);
    const existing = store.getThreadSession(threadKey);
    if (existing) {
      const session = await composio.sessions.use(existing.sessionId);
      await pinSlackbotConnectionIfAllowed(config, event, session, existing.userId, slackbotConnectedAccountId);
      return session;
    }

    if (slackbotConnectedAccountId) {
      assertSlackbotManualAcl(event, userId);
    }

    const session = await composio.sessions.create(userId, {
      manageConnections: {
        enable: true,
        callbackUrl: authCallbackUrl(config, event),
        waitForConnections: true,
      },
      workbench: {
        enable: config.composioWorkbenchEnabled,
      },
      ...(config.composioToolkits ? { toolkits: withSlackbotToolkit(config.composioToolkits, slackbotConnectedAccountId) } : {}),
      ...(config.composioAuthConfigs ? { authConfigs: config.composioAuthConfigs } : {}),
      ...(slackbotConnectedAccountId
        ? {
            connectedAccounts: {
              slackbot: [slackbotConnectedAccountId],
            },
          }
        : {}),
    });

    await store.setThreadSession(threadKey, session.sessionId, userId);
    return session;
  };

  const createPiComposioTools: ComposioRouting['createPiComposioTools'] = (event, userSession, handleAuthLinks) =>
    piProvider.createSessionTools(createPiCapabilities({ config, event, handleAuthLinks, userSession }));

  return {
    createPiComposioTools,
    getOrCreateUserSession,
  };
}

function createPiCapabilities({ config, event, handleAuthLinks, userSession }: CapabilityDeps): PiSessionToolCapabilities {
  const callbackUrl = authCallbackUrl(config, event);
  const includeWorkbenchTools = config.composioWorkbenchEnabled;

  return {
    callbackUrl,
    includeWorkbenchTools,
    sessionId: userSession.sessionId,
    search: (params) =>
      userSession.search({
        query: params.query,
        ...(params.toolkits ? { toolkits: params.toolkits } : {}),
      }),
    execute: async (toolSlug, args, options) => {
      if (isSlackbotToolSlug(toolSlug)) {
        assertSlackbotManualAcl(event, slackUserComposioId(event));
      }

      return userSession.execute(toolSlug, args, {
        ...(options?.account ? { account: options.account } : {}),
      });
    },
    connections: {
      getToolkitStates: async (toolkits) => {
        const normalizedToolkits = normalizeRequestedToolkits(toolkits) ?? [];
        const userToolkits = normalizedToolkits.filter(isUserAuthToolkit);
        const userStates = userToolkits.length > 0 ? normalizeToolkitStates(await userSession.toolkits({ toolkits: userToolkits })) : [];
        return {
          items: [
            ...normalizedToolkits.filter((toolkit) => !isUserAuthToolkit(toolkit)).map(syntheticConnectedToolkitState),
            ...userStates,
          ],
        };
      },
      authorizeToolkit: async (toolkit) => {
        if (!isUserAuthToolkit(toolkit)) {
          return slackbotAlreadyConnectedResult([toolkit]);
        }

        const request = await userSession.authorize(toolkit, { callbackUrl });
        return {
          status: 'needs_connection',
          redirectUrl: request.redirectUrl ?? null,
        };
      },
      isConnected: (state) => toolkitIsConnectedFromUnknown(state),
    },
    hooks: {
      search: (context, next) => {
        context.request.toolkits = normalizeSearchToolkits(context.request.toolkits) ?? undefined;
        return next();
      },
      execute: (context, next) => {
        const trimmedSlug = context.request.toolSlug.trim();

        if (isUserSlackToolSlug(trimmedSlug)) {
          return context.deny(USE_SLACKBOT_INSTEAD_ERROR);
        }

        if (trimmedSlug === 'COMPOSIO_MANAGE_CONNECTIONS') {
          return context.deny(USE_DEDICATED_MANAGE_CONNECTIONS_ERROR);
        }

        if (isSlackbotToolSlug(trimmedSlug)) {
          assertSlackbotManualAcl(event, slackUserComposioId(event));
        }

        context.request.toolSlug = trimmedSlug;
        return next();
      },
      onAuthLink: (context) => handleAuthLinks(context.result, context.sourceTool, context.toolkit ? [context.toolkit] : undefined),
    },
    transformResult: async ({ value, tool, requestedToolkits, context }) => {
      const sourceTool = context?.sourceTool ?? providerToolName(tool);
      return handleAuthLinks(value, sourceTool, requestedToolkits);
    },
  };
}

async function pinSlackbotConnectionIfAllowed(
  config: AppConfig,
  event: NormalizedSlackTriggerEvent,
  session: ComposioSession,
  userId: string,
  slackbotConnectedAccountId: string | undefined,
): Promise<void> {
  if (!slackbotConnectedAccountId) return;

  assertSlackbotManualAcl(event, userId);
  await session.update({
    ...(config.composioToolkits ? { toolkits: withSlackbotToolkit(config.composioToolkits, slackbotConnectedAccountId) } : {}),
    connectedAccounts: {
      slackbot: [slackbotConnectedAccountId],
    },
  });
}

function slackbotConnectedAccountIdForEvent(
  config: AppConfig,
  store: Store,
  event: NormalizedSlackTriggerEvent,
): string | undefined {
  return config.slackbotSharedConnectedAccountId ?? store.getSlackbotConnection(event.teamId)?.connectedAccountId ?? event.connectedAccountId;
}

function withSlackbotToolkit(toolkits: string[], slackbotConnectedAccountId: string | undefined): string[] {
  if (!slackbotConnectedAccountId || toolkits.includes('slackbot')) return toolkits;
  return [...toolkits, 'slackbot'];
}

function isUserAuthToolkit(toolkit: string): boolean {
  const normalized = normalizeToolkitKey(toolkit);
  return Boolean(normalized && normalized !== 'slack' && normalized !== 'slackbot');
}

function syntheticConnectedToolkitState(toolkit: string): JsonObject {
  return {
    slug: normalizeToolkitKey(toolkit) === 'slack' ? 'slackbot' : toolkit,
    isNoAuth: true,
    connection: {
      isActive: true,
      connectedAccount: {
        status: 'ACTIVE',
      },
    },
  };
}

function toolkitIsConnectedFromUnknown(value: unknown): boolean {
  const states = normalizeToolkitStates({ items: [value] });
  return toolkitIsConnected(states[0]);
}

function providerToolName(tool: string): string {
  const names: Record<string, string> = {
    execute: 'composio_execute_tool',
    manageConnections: 'COMPOSIO_MANAGE_CONNECTIONS',
    remoteBash: 'COMPOSIO_REMOTE_BASH_TOOL',
    remoteWorkbench: 'COMPOSIO_REMOTE_WORKBENCH',
    search: 'composio_search_tools',
  };
  return names[tool] ?? tool;
}

function slackUserComposioId(event: NormalizedSlackTriggerEvent): string {
  return `slack:${event.teamId}:${event.userId}`;
