export interface HandleSlackMessageOptions {
  autoAnalyze?: boolean;
}

export interface SlackComposioAgent {
  handleSlackMessage(event: NormalizedSlackTriggerEvent, options?: HandleSlackMessageOptions): Promise<void>;
}

interface AgentDeps {
  config: AppConfig;
  slack: SlackTransport;
  store: Store;
}

export function createSlackComposioAgent({ config, slack, store }: AgentDeps): SlackComposioAgent {
  const composio = new Composio({ apiKey: config.composioApiKey });
  const composioRouting = createComposioRouting({ composio, config, store });

  const postSlackResponse = async (
    channel: string,
    threadTs: string | undefined,
    text: string,
    event: NormalizedSlackTriggerEvent,
  ): Promise<void> => {
    for (const chunk of splitForSlack(text)) {
      await slack.postMessage({ channel, threadTs, text: chunk }, event);
    }
  };

  const handleSlackMessage = async (
    event: NormalizedSlackTriggerEvent,
    options: HandleSlackMessageOptions = {},
  ): Promise<void> => {
    const threadKey = slackThreadKey(event);
    const userId = composioUserIdForSlack(event);
    const botUserId = store.getSlackbotConnection(event.teamId)?.botUserId ?? config.slackBotUserId;
    const prompt = cleanSlackPrompt(event.text, botUserId);
    const replyThreadTs = replyThreadTimestamp(event);

    if (!prompt) {
      if (options.autoAnalyze) {
        await slack.addReaction(event.channel, event.ts, config.ignoreReactionName, event);
        return;
      }

      await slack.postMessage(
        {
          channel: event.channel,
          threadTs: replyThreadTs,
          text: "Hi! Ask me to do something across your connected apps, and I'll help.",
        },
        event,
      );
      return;
    }

    const history = store.getHistory(threadKey);
    const [slackThreadMessages, slackUserContext] = await Promise.all([
      fetchSlackThreadContext(slack, event),
      fetchSlackUserContext(slack, event),
    ]);
    if (options.autoAnalyze) {
      const shouldRespond = await shouldRespondToMainUserMessage({ config, event, history, prompt, slackThreadMessages });
      if (!shouldRespond) {
        await slack.addReaction(event.channel, event.ts, config.ignoreReactionName, event);
        return;
      }
    }

    void slack.setThreadStatus(
      {
        channel: event.channel,
        threadTs: event.threadTs,
        status: claudeStyleStatus(`${threadKey}:${prompt}`),
      },
      event,
    );

    if (!event.isDirectMessage) {
      void slack.addReaction(event.channel, event.ts, 'eyes', event);
    }

    const composioSession = await composioRouting.getOrCreateUserSession(event, userId, threadKey);
    const threadOwnerUserId = store.getThreadSession(threadKey)?.userId ?? userId;
    const authCollector = createAuthLinkCollector({ store, threadKey });
    const tools = composioRouting.createPiComposioTools(event, composioSession, authCollector.handleAuthLinks);

    const assistantText = await runPiAgent({
      config,
      event,
      history,
      prompt,
      slackThreadMessages,
      systemPrompt: buildSystemPrompt(config, event, composioSession.sessionId, slackUserContext, threadOwnerUserId),
      tools,
    });

    const sentAuthDm = authCollector.pendingLinks.length > 0;
    if (sentAuthDm) {
      await slack.postDm(event.userId, formatConnectionDm(authCollector.pendingLinks, prompt), event);
    }

    const authLabels = sentAuthDm ? authLabelsForLinks(authCollector.pendingLinks) : [];
    const authLabelText = sentAuthDm ? formatAuthLabelList(authLabels) : '';
    const text = redactString(
      sentAuthDm
        ? `I sent you a DM to connect ${authLabelText}. After approving access, I’ll continue automatically.`
        : assistantText || 'Done.',
    );

    if (sentAuthDm) {
      await store.setPendingAuthContinuation({
        authLabels,
        channel: event.channel,
        event: resumableEvent(event),
        prompt,
        teamId: event.teamId,
        threadKey,
        threadTs: event.threadTs,
        userId: event.userId,
      });
      const publicMessageTs = await slack.postMessage({ channel: event.channel, threadTs: replyThreadTs, text }, event);
      if (publicMessageTs) {
        await store.setPendingAuthPublicMessageTs(threadKey, publicMessageTs);
      }
    } else {
      await postSlackResponse(event.channel, replyThreadTs, text, event);
    }

    void slack.clearThreadStatus({ channel: event.channel, threadTs: event.threadTs }, event);
    await store.appendHistory(threadKey, [
      { role: 'user', content: prompt },
      { role: 'assistant', content: text },
    ]);
  };

  return { handleSlackMessage };
}

function resumableEvent(event: NormalizedSlackTriggerEvent) {
  return {
    botId: event.botId,
    channel: event.channel,
    channelType: event.channelType,
    connectedAccountId: event.connectedAccountId,
    eventKey: `auth-resume:${event.eventKey}`,
    isDirectMessage: event.isDirectMessage,
    subtype: event.subtype,
    teamId: event.teamId,
    text: event.text,
    threadTs: event.threadTs,
    triggerSlug: event.triggerSlug,
    ts: event.ts,
    userId: event.userId,
  };
}

function buildSystemPrompt(
  config: AppConfig,
  event: NormalizedSlackTriggerEvent,
  composioSessionId: string,
  slackUserContext: SlackUserContext,
  threadOwnerUserId: string,
): string {
  return [
    'You are Pi running as the brain of a Slack assistant. You are concise, practical, and action-oriented.',
    config.composioWorkbenchEnabled
      ? 'You have access to Composio remote workbench tools through the Composio session. Use composio_search_tools to find workbench tools, then composio_execute_tool to run them for scratch files, analysis, transformations, and code execution in Composio’s remote sandbox.'
      : 'Composio remote workbench tools are disabled in this deployment.',
    config.piWorkbenchEnabled
      ? `Local Pi workbench tools are also enabled at ${config.piCwd}. Prefer Composio remote workbench for untrusted code or larger execution tasks.`
      : 'Local Pi filesystem/bash tools are disabled; use Composio remote workbench for code/scratch execution.',
    'You have three Composio tools: search tools, manage connections, and execute tools. Use them to work across the Slack user’s connected apps.',
    'You are given the full Slack thread context fetched from Slack before the incoming message. Treat that thread context as the source of truth for conversation state, user instructions, prior decisions, and what has already been tried.',
    formatSlackUserContext(slackUserContext),
    'Use the Slack requester timezone/local time when interpreting relative dates and times like today, tomorrow, next Friday, morning, EOD, or scheduling defaults.',
    'composio_search_tools is global by default. Only pass a toolkits filter when intentionally narrowing the search.',
    'For Slack workspace actions outside the current conversation, search with toolkits ["slackbot"] and execute SLACKBOT_* tools. Never use the user-scoped slack toolkit and never ask the user to connect Slack for Slack workspace actions.',
    'For requests to say/reply/post something in the current Slack conversation, simply make that text your final response. Do not use Slack/Slackbot Composio tools or ask the user to connect Slack for current-conversation replies.',
    'Always use the current user-scoped Composio session for non-Slackbot app actions. Never ask for API keys or OAuth secrets in Slack.',
    'When a required non-Slack app is not connected, call composio_manage_connections. The system will DM auth links to the user, wait for approval when supported, and redact links from tool output.',
    'Never reveal Composio connection links, OAuth URLs, or raw credentials in your final Slack response.',
    'If a tool says a connection link was sent via Slack DM, tell the user to approve it and that you will continue automatically.',
    'If the user says “done”, “connected”, or similar after an auth step, continue the previous task from the conversation context.',
    'Ask before destructive or irreversible actions unless the user explicitly requested the action.',
    'Use Slack mrkdwn in final responses.',
    `Composio session id: ${composioSessionId}`,
    `Thread owner Composio user id: ${threadOwnerUserId}. Incoming Slack requester: slack:${event.teamId}:${event.userId}. For user-scoped app actions, this thread uses the thread owner's Composio session unless a new thread is started.`,
    `Slack context: team=${event.teamId}, channel=${event.channel}, thread_ts=${event.threadTs}, user=${event.userId}.`,
  ].join('\n');
}

function formatSlackUserContext(context: SlackUserContext): string {
  const fields = [
    `user=${context.userId}`,
    context.timeZone ? `timezone=${context.timeZone}` : undefined,
    context.timeZoneLabel ? `timezone_label=${context.timeZoneLabel}` : undefined,
    typeof context.timeZoneOffsetSeconds === 'number' ? `timezone_offset_seconds=${context.timeZoneOffsetSeconds}` : undefined,
    context.localTime ? `current_local_time=${context.localTime}` : undefined,
    context.locale ? `locale=${context.locale}` : undefined,
  ].filter(Boolean);
  return `Slack requester context: ${fields.join(', ')}.`;
}

async function fetchSlackThreadContext(
  slack: SlackTransport,
  event: NormalizedSlackTriggerEvent,
): Promise<SlackThreadMessage[]> {
  try {
    return ensureIncomingEventInThread(
      await slack.fetchThreadMessages({ channel: event.channel, threadTs: event.threadTs }, event),
      event,
    );
  } catch (error) {
    console.warn('Failed to fetch Slack thread context', error instanceof Error ? error.message : String(error));
    return [threadMessageFromEvent(event)];
  }
}

async function fetchSlackUserContext(slack: SlackTransport, event: NormalizedSlackTriggerEvent): Promise<SlackUserContext> {
  try {
    return await slack.fetchUserContext(event.userId, event);
  } catch (error) {
    console.warn('Failed to fetch Slack user timezone context', error instanceof Error ? error.message : String(error));
    return { userId: event.userId };
  }
}

function ensureIncomingEventInThread(
  messages: SlackThreadMessage[],
  event: NormalizedSlackTriggerEvent,
): SlackThreadMessage[] {
  if (messages.some((message) => message.ts === event.ts)) return messages;
  return [...messages, threadMessageFromEvent(event)].sort((left, right) => Number(left.ts) - Number(right.ts));
}

function threadMessageFromEvent(event: NormalizedSlackTriggerEvent): SlackThreadMessage {
  return {
    botId: event.botId,
    isBot: Boolean(event.botId),
    subtype: event.subtype,
    text: event.text,
    ts: event.ts,
    userId: event.userId,
  };
}

function replyThreadTimestamp(event: NormalizedSlackTriggerEvent): string | undefined {
  if (event.isDirectMessage && event.threadTs === event.ts) return undefined;
  return event.threadTs;
}

function splitForSlack(text: string, maxLength = 3600): string[] {
  if (text.length <= maxLength) return [text];

  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > maxLength) {
    const breakpoint = Math.max(remaining.lastIndexOf('\n', maxLength), remaining.lastIndexOf(' ', maxLength));
    const index = breakpoint > maxLength * 0.5 ? breakpoint : maxLength;
    chunks.push(remaining.slice(0, index).trim());
    remaining = remaining.slice(index).trim();
  }
  if (remaining) chunks.push(remaining);
  return chunks;
}

import type { SlackComposioAgent } from '../agent/slack-composio-agent';
import type { AppConfig } from '../config/env';
import {
  composioUserIdForSlack,
  isProcessableSlackEvent,
  messageMentionsBot,
  normalizeComposioSlackEvent,
  slackMessageDedupeKey,
  slackThreadKey,
} from '../slack/events';
import type { Store } from '../store/file-store';

interface ComposioWebhookHandlerDeps {
  agent: SlackComposioAgent;
  config: AppConfig;
  store: Store;
}

export interface ComposioWebhookHandler {
  processPayload(body: unknown): Promise<Record<string, unknown>>;
}

export function createComposioWebhookHandler({ agent, config, store }: ComposioWebhookHandlerDeps): ComposioWebhookHandler {
  const inFlightDedupeKeys = new Set<string>();

  const processPayload = async (body: unknown): Promise<Record<string, unknown>> => {
    const event = normalizeComposioSlackEvent(body);
    if (!event) {
      return { ok: true, ignored: 'not_a_slack_trigger_payload' };
    }

    const dedupeKeys = [event.eventKey, slackMessageDedupeKey(event)];
    if (dedupeKeys.some((key) => inFlightDedupeKeys.has(key) || store.hasProcessedEvent(key))) {
      return { ok: true, duplicate: true };
    }

    for (const key of dedupeKeys) inFlightDedupeKeys.add(key);
    try {
      await Promise.all(dedupeKeys.map((key) => store.markProcessedEvent(key)));
    } finally {
      for (const key of dedupeKeys) inFlightDedupeKeys.delete(key);
    }

    const botUserId = store.getSlackbotConnection(event.teamId)?.botUserId ?? config.slackBotUserId;
    if (!isProcessableSlackEvent(event, botUserId)) {
      return { ok: true, ignored: 'not_processable' };
    }

    const mentionedBot = messageMentionsBot(event, botUserId);
    const configuredMainUser = config.mainSlackUserIds.includes(event.userId);
    if (configuredMainUser) {
      await store.addMainSlackUser(event.teamId, event.userId);
    }

    if (
      config.autoPromoteFirstMainUser &&
      store.getMainSlackUsers(event.teamId).length === 0 &&
      (mentionedBot || event.isDirectMessage)
    ) {
      await store.addMainSlackUser(event.teamId, event.userId);
    }

    const isMainUser = store.isMainSlackUser(event.teamId, event.userId) || configuredMainUser;
    const threadSession = store.getThreadSession(slackThreadKey(event));
    const isThreadOwner = threadSession?.userId === composioUserIdForSlack(event);
    const shouldHandleNormally = event.isDirectMessage || mentionedBot;
    const shouldAutoAnalyze =
      !shouldHandleNormally &&
      ((config.autoAnalyzeMainUserMessages && isMainUser) || Boolean(threadSession && isThreadOwner));

    if (!shouldHandleNormally && !shouldAutoAnalyze) {
      return { ok: true, ignored: 'requires_mention' };
    }

    queueMicrotask(() => {
      agent.handleSlackMessage(event, { autoAnalyze: shouldAutoAnalyze }).catch((error) => {
        console.error('Failed to handle Slack event', error);
      });
    });

    return { ok: true, accepted: true, autoAnalyze: shouldAutoAnalyze };
  };

  return { processPayload };
}

import { Composio } from '@composio/core';

import type { AppConfig } from '../config/env';
import type { Store } from '../store/file-store';
import { firstString, jsonObject } from '../utils/decode';
import type { JsonObject, JsonValue } from '../utils/json';
import type { NormalizedSlackTriggerEvent } from './events';

type ComposioSession = Awaited<ReturnType<Composio['sessions']['create']>>;

type CachedSlackUserContext = {
  context: SlackUserContext;
  expiresAt: number;
  refresh?: Promise<SlackUserContext>;
};

const USER_CONTEXT_CACHE_TTL_MS = 6 * 60 * 60 * 1000;

export interface SlackMessageOptions {
  channel: string;
  text: string;
  threadTs?: string;
}

export interface SlackUpdateMessageOptions {
  channel: string;
  text: string;
  ts: string;
}

export interface SlackThreadStatusOptions {
  channel: string;
  loadingMessages?: string[];
  status: string;
  threadTs: string;
}

export interface SlackThreadMessage {
  botId?: string | null;
  isBot: boolean;
  subtype?: string | null;
  text: string;
  ts: string;
  userId?: string;
  username?: string;
}

export interface SlackFetchThreadOptions {
  channel: string;
  maxMessages?: number;
  threadTs: string;
}

export interface SlackUserContext {
  locale?: string;
  localTime?: string;
  timeZone?: string;
  timeZoneLabel?: string;
  timeZoneOffsetSeconds?: number;
  userId: string;
}

export interface SlackTransport {
  addReaction(channel: string, timestamp: string, name: string, event?: NormalizedSlackTriggerEvent): Promise<void>;
  clearThreadStatus(options: Omit<SlackThreadStatusOptions, 'loadingMessages' | 'status'>, event?: NormalizedSlackTriggerEvent): Promise<void>;
  fetchThreadMessages(options: SlackFetchThreadOptions, event?: NormalizedSlackTriggerEvent): Promise<SlackThreadMessage[]>;
  fetchUserContext(userId: string, event?: NormalizedSlackTriggerEvent): Promise<SlackUserContext>;
  postDm(userId: string, text: string, event?: NormalizedSlackTriggerEvent): Promise<string | undefined>;
  postMessage(options: SlackMessageOptions, event?: NormalizedSlackTriggerEvent): Promise<string | undefined>;
  updateMessage(options: SlackUpdateMessageOptions, event?: NormalizedSlackTriggerEvent): Promise<void>;
  setThreadStatus(options: SlackThreadStatusOptions, event?: NormalizedSlackTriggerEvent): Promise<void>;
}

interface SlackTransportDeps {
  config: AppConfig;
  store: Store;
}

/**
 * Slack transport backed by a Composio Slackbot connected account.
 * The Slack bot token stays in Composio; this app stores only ca_* ids.
 */
export function createSlackTransport({ config, store }: SlackTransportDeps): SlackTransport {
  const composio = new Composio({ apiKey: config.composioApiKey });
  const dmChannels = new Map<string, string>();
  const sessions = new Map<string, ComposioSession>();
  const userContexts = new Map<string, CachedSlackUserContext>();

  const sessionForEvent = async (event?: NormalizedSlackTriggerEvent): Promise<ComposioSession> => {
    const connectedAccountId = connectedAccountIdForEvent(config, store, event);
    const cached = sessions.get(connectedAccountId);
    if (cached) return cached;

    const session = await composio.sessions.create(transportUserIdForEvent(config, event), {
      toolkits: ['slackbot'],
      connectedAccounts: {
        slackbot: [connectedAccountId],
      },
      manageConnections: false,
      workbench: { enable: false },
    });

    sessions.set(connectedAccountId, session);
    return session;
  };

  const openDm = async (userId: string, event?: NormalizedSlackTriggerEvent): Promise<string> => {
    const cacheKey = `${connectedAccountIdForEvent(config, store, event)}:${userId}`;
    const cached = dmChannels.get(cacheKey);
    if (cached) return cached;

    const session = await sessionForEvent(event);
    const response = await proxySlack(session, 'conversations.open', { users: userId });
    const channelId = decodeOpenDmChannelId(response);
    if (!channelId) {
      throw new Error(`Slack conversations.open did not return a channel id for user ${userId}: ${JSON.stringify(response)}`);
    }

    dmChannels.set(cacheKey, channelId);
    return channelId;
  };

  const postMessage = async (
    { channel, text, threadTs }: SlackMessageOptions,
    event?: NormalizedSlackTriggerEvent,
  ): Promise<string | undefined> => {
    const session = await sessionForEvent(event);
    const response = await proxySlack(session, 'chat.postMessage', {
      channel,
      text,
      mrkdwn: true,
      thread_ts: threadTs,
      unfurl_links: false,
      unfurl_media: false,
    });

    return decodePostMessageTimestamp(response);
  };

  const updateMessage = async (
    { channel, text, ts }: SlackUpdateMessageOptions,
    event?: NormalizedSlackTriggerEvent,
  ): Promise<void> => {
    const session = await sessionForEvent(event);
    await proxySlack(session, 'chat.update', {
      channel,
      ts,
      text,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
  };

  const setThreadStatus = async (
    { channel, threadTs, status, loadingMessages }: SlackThreadStatusOptions,
    event?: NormalizedSlackTriggerEvent,
  ): Promise<void> => {
    try {
      const session = await sessionForEvent(event);
      await proxySlack(session, 'assistant.threads.setStatus', {
        channel_id: channel,
        thread_ts: threadTs,
        status,
        loading_messages: loadingMessages,
      });
    } catch (error) {
      // Status indicators are optional polish. Missing Slack AI app capability should not break replies.
      console.warn('Failed to set Slack assistant thread status', summarizeError(error));
    }
  };

  const fetchThreadMessages = async (
    { channel, threadTs, maxMessages = Number.MAX_SAFE_INTEGER }: SlackFetchThreadOptions,
    event?: NormalizedSlackTriggerEvent,
  ): Promise<SlackThreadMessage[]> => {
    const session = await sessionForEvent(event);
    const messages: SlackThreadMessage[] = [];
    let cursor: string | undefined;

    do {
      const response = await proxySlackGet(session, 'conversations.replies', {
        channel,
        ts: threadTs,
        limit: Math.min(200, Math.max(1, maxMessages - messages.length)),
        cursor,
      });
      messages.push(...decodeThreadMessages(response));
      cursor = decodeNextCursor(response);
    } while (cursor && messages.length < maxMessages);

    return messages.slice(0, maxMessages);
  };

  const requestUserContext = async (userId: string, event?: NormalizedSlackTriggerEvent): Promise<SlackUserContext> => {
    const session = await sessionForEvent(event);
    const response = await proxySlackGet(session, 'users.info', {
      user: userId,
      include_locale: 'true',
    });
    return decodeUserContext(response, userId);
  };

  const refreshUserContext = (cacheKey: string, userId: string, event?: NormalizedSlackTriggerEvent): Promise<SlackUserContext> => {
    const refresh = requestUserContext(userId, event)
      .then((context) => {
        const cached = {
          context,
          expiresAt: Date.now() + USER_CONTEXT_CACHE_TTL_MS,
        };
        userContexts.set(cacheKey, cached);
        return withFreshLocalTime(context);
      })
      .catch((error) => {
        const existing = userContexts.get(cacheKey);
        if (existing) {
          userContexts.set(cacheKey, { context: existing.context, expiresAt: existing.expiresAt });
        }
        throw error;
      });

    const existing = userContexts.get(cacheKey);
    if (existing) {
      userContexts.set(cacheKey, { ...existing, refresh });
    }
    return refresh;
  };

  const fetchUserContext = async (userId: string, event?: NormalizedSlackTriggerEvent): Promise<SlackUserContext> => {
    const cacheKey = `${connectedAccountIdForEvent(config, store, event)}:${userId}`;
    const now = Date.now();
    const cached = userContexts.get(cacheKey);
    if (cached && cached.expiresAt > now) {
      return withFreshLocalTime(cached.context);
    }

    if (cached) {
      if (!cached.refresh) {
        const refresh = refreshUserContext(cacheKey, userId, event).catch((error) => {
          console.warn('Failed to refresh cached Slack user timezone context', summarizeError(error));
          return withFreshLocalTime(cached.context);
        });
        userContexts.set(cacheKey, { ...cached, refresh });
      }
      return withFreshLocalTime(cached.context);
    }

    const fallback = { userId };
    const refresh = refreshUserContext(cacheKey, userId, event).catch((error) => {
      console.warn('Failed to fetch Slack user timezone context', summarizeError(error));
      return fallback;
    });
    userContexts.set(cacheKey, {
      context: fallback,
      expiresAt: 0,
      refresh,
    });
    return fallback;
  };

  return {
    addReaction: async (channel, timestamp, name, event) => {
      try {
        const session = await sessionForEvent(event);
        await proxySlack(session, 'reactions.add', { channel, timestamp, name });
      } catch (error) {
        // Reactions are optional polish. Missing scopes or duplicate reactions should not break handling.
        console.warn('Failed to add Slack reaction', summarizeError(error));
      }
    },

    clearThreadStatus: async ({ channel, threadTs }, event) => {
      await setThreadStatus({ channel, threadTs, status: '' }, event);
    },

    fetchThreadMessages,
    fetchUserContext,

    postDm: async (userId, text, event) => {
      const channel = await openDm(userId, event);
      return postMessage({ channel, text }, event);
    },

    postMessage,
    setThreadStatus,
    updateMessage,
  };
}

export async function proxySlack(
  session: ComposioSession,
  method: string,
  body: Record<string, JsonValue | undefined>,
): Promise<JsonValue> {
  const response = await session.proxyExecute({
    toolkit: 'slackbot',
    endpoint: `https://slack.com/api/${method}`,
    method: 'POST',
    body: stripUndefined(body),
  });

  return decodeSlackApiResponse(method, response);
}

async function proxySlackGet(
  session: ComposioSession,
  method: string,
  query: Record<string, string | number | undefined>,
): Promise<JsonValue> {
  const response = await session.proxyExecute({
    toolkit: 'slackbot',
    endpoint: `https://slack.com/api/${method}`,
    method: 'GET',
    parameters: queryParameters(query),
  });

  return decodeSlackApiResponse(method, response);
}

function decodeSlackApiResponse(method: string, response: unknown): JsonValue {
  const responseObject = jsonObject(response) ?? {};
  const slackPayload = jsonObject(responseObject.data) ?? responseObject;

  if (slackPayload.ok === false) {
    throw new Error(`Slack API ${method} failed: ${firstString(slackPayload.error) ?? JSON.stringify(slackPayload)}`);
  }

  return slackPayload;
}

function decodeOpenDmChannelId(response: JsonValue): string | undefined {
  const payload = jsonObject(response) ?? {};
  const channel = jsonObject(payload.channel) ?? jsonObject(jsonObject(payload.data)?.channel);
  return firstString(channel?.id);
}

function decodePostMessageTimestamp(response: JsonValue): string | undefined {
  const payload = jsonObject(response) ?? {};
  const data = jsonObject(payload.data);
  const message = jsonObject(payload.message);
  return firstString(payload.ts, data?.ts, message?.ts);
}

function decodeThreadMessages(response: JsonValue): SlackThreadMessage[] {
  const payload = jsonObject(response) ?? {};
  const rawMessages = Array.isArray(payload.messages) ? payload.messages : [];

  return rawMessages.flatMap((rawMessage): SlackThreadMessage[] => {
    const message = jsonObject(rawMessage);
    const ts = firstString(message?.ts);
    if (!message || !ts) return [];

    return [
      {
        botId: firstString(message.bot_id, message.botId) ?? null,
        isBot: Boolean(firstString(message.bot_id, message.botId)) || typeof message.bot_profile === 'object',
        subtype: firstString(message.subtype) ?? null,
        text: messageTextWithFiles(message),
        ts,
        userId: firstString(message.user, message.user_id, message.userId),
        username: firstString(message.username, message.user_name, message.userName),
      },
    ];
  });
}

function decodeNextCursor(response: JsonValue): string | undefined {
  const payload = jsonObject(response) ?? {};
  const metadata = jsonObject(payload.response_metadata) ?? jsonObject(payload.responseMetadata);
  return firstString(metadata?.next_cursor, metadata?.nextCursor);
}

function decodeUserContext(response: JsonValue, fallbackUserId: string): SlackUserContext {
  const payload = jsonObject(response) ?? {};
  const data = jsonObject(payload.data);
  const user = jsonObject(payload.user) ?? jsonObject(data?.user) ?? {};
  const profile = jsonObject(user.profile) ?? {};
  const timeZone = firstString(user.tz, user.timezone, profile.tz, profile.timezone);

  return {
    locale: firstString(user.locale, profile.locale),
    localTime: timeZone ? formatLocalTime(timeZone) : undefined,
    timeZone,
    timeZoneLabel: firstString(user.tz_label, user.tzLabel),
    timeZoneOffsetSeconds: firstNumber(user.tz_offset, user.tzOffset),
    userId: firstString(user.id) ?? fallbackUserId,
  };
}

function messageTextWithFiles(message: JsonObject): string {
  const text = firstString(message.text) ?? '';
  const files = Array.isArray(message.files) ? message.files : [];
  const fileSummaries = files.flatMap((rawFile): string[] => {
    const file = jsonObject(rawFile);
    if (!file) return [];
    const title = firstString(file.title, file.name) ?? 'file';
    const url = firstString(file.permalink, file.url_private, file.urlPrivate);
    return [url ? `[file: ${title} ${url}]` : `[file: ${title}]`];
  });

  return [text, ...fileSummaries].filter(Boolean).join('\n');
}

function firstNumber(...values: unknown[]): number | undefined {
  for (const value of values) {
    if (typeof value === 'number' && Number.isFinite(value)) return value;
    if (typeof value !== 'string' || !value.trim()) continue;
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return undefined;
}

function withFreshLocalTime(context: SlackUserContext): SlackUserContext {
  return {
    ...context,
    localTime: context.timeZone ? formatLocalTime(context.timeZone) : undefined,
  };
}

function formatLocalTime(timeZone: string): string | undefined {
  try {
    return new Intl.DateTimeFormat('en-US', {
      dateStyle: 'full',
      timeStyle: 'long',
      timeZone,
    }).format(new Date());
  } catch {
    return undefined;
  }
}

function connectedAccountIdForEvent(config: AppConfig, store: Store, event?: NormalizedSlackTriggerEvent): string {
  const id =
    config.slackbotSharedConnectedAccountId ??
    event?.connectedAccountId ??
    (event?.teamId ? store.getSlackbotConnection(event.teamId)?.connectedAccountId : undefined);
  if (!id) {
    throw new Error(
      'Missing Slackbot transport connected account. Open /setup/slackbot/start to install Slackbot or set SLACKBOT_SHARED_CONNECTED_ACCOUNT_ID.',
    );
  }
  return id;
}

function transportUserIdForEvent(config: AppConfig, event?: NormalizedSlackTriggerEvent): string {
  if (config.slackbotTransportUserId) return config.slackbotTransportUserId;
  if (!event?.teamId || event.teamId === 'unknown-team') {
    throw new Error('Missing Slack team id; cannot derive Slackbot transport user id service:${teamId}.');
  }
  return `service:${event.teamId}`;
}

function stripUndefined(value: Record<string, JsonValue | undefined>): JsonObject {
  return Object.fromEntries(Object.entries(value).filter(([, nested]) => nested !== undefined)) as JsonObject;
}

function queryParameters(value: Record<string, string | number | undefined>): Array<{ in: 'query'; name: string; value: string | number }> {
  return Object.entries(value).flatMap(([name, nested]) => (nested === undefined ? [] : [{ in: 'query' as const, name, value: nested }]));
}

function summarizeError(error: Error | unknown): string {
  if (error instanceof Error) return error.message;
  return String(error);
}

import type { NormalizedSlackTriggerEvent } from './events';

export function assertSlackbotManualAcl(event: NormalizedSlackTriggerEvent, composioUserId: string): void {
  if (isAllowedSlackbotUserId(event.teamId, composioUserId)) return;

  throw new Error(
    `Refusing to pin Slackbot shared connection for ${composioUserId}. ` +
      `Allowed patterns: ${slackbotAllowedUserIdPatterns(event.teamId).join(', ')}`,
  );
}

export function isAllowedSlackbotUserId(teamId: string, composioUserId: string): boolean {
  return composioUserId === `service:${teamId}` || composioUserId.startsWith(`slack:${teamId}:`);
}

export function slackbotAllowedUserIdPatterns(teamId: string): string[] {
  return [`service:${teamId}`, `slack:${teamId}:*`];
}
